import React, { useEffect, useState } from "react";
import { supabase } from "../supabaseClient";
import { LogOut, RefreshCcw, User, MapPin, Clock } from "lucide-react";

const Dashboard = ({ session }) => {
  const [rides, setRides] = useState([]);

  useEffect(() => {
    fetchRides();

    // REAL-TIME LISTENER: Jaise hi database mein naya data aaye
    const channel = supabase
      .channel('realtime-rides')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'rides' }, (payload) => {
        setRides((prev) => [payload.new, ...prev]);
      })
      .subscribe();

    return () => supabase.removeChannel(channel);
  }, []);

  const fetchRides = async () => {
    const { data } = await supabase
      .from("rides")
      .select("*")
      .order("created_at", { ascending: false });
    setRides(data || []);
  };

  const handleLogout = () => supabase.auth.signOut();

  return (
    <div className="dashboard-container">
      <nav className="admin-nav">
        <h1>PAHEL Admin</h1>
        <div className="nav-actions">
          <span>{session.user.email}</span>
          <button onClick={handleLogout} className="logout-btn"><LogOut size={18} /></button>
        </div>
      </nav>

      <div className="table-section">
        <div className="table-header">
          <h3>Recent Bookings</h3>
          <button onClick={fetchRides} className="refresh-btn"><RefreshCcw size={16} /></button>
        </div>

        <table className="admin-table">
          <thead>
            <tr>
              <th>Passenger</th>
              <th>Locations</th>
              <th>Scheduled For</th>
              <th>Vehicle</th>
            </tr>
          </thead>
          <tbody>
            {rides.map((ride) => (
              <tr key={ride.id}>
                <td><strong>{ride.passenger_name}</strong><br/>{ride.phone_number}</td>
                <td>
                  <div className="loc"><MapPin size={12} color="green"/> {ride.pickup_location}</div>
                  <div className="loc"><MapPin size={12} color="red"/> {ride.drop_location}</div>
                </td>
                <td>{ride.ride_date}<br/><strong>{ride.ride_time}</strong></td>
                <td><span className="v-tag">{ride.vehicle_class}</span></td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Dashboard;
